    template_colors = set()
    for r in range(H):
        for c in range(W):
            v = grid[r, c]
            if v not in (0, 1, 5):
                template_colors.add(int(v))

    # For each template color, find its bounding box and count hole components
    hole_to_color = {}
    for color in template_colors:
        positions = list(zip(*np.where(grid == color)))
        if not positions:
            continue
        rows_c = [r for r, c in positions]
        cols_c = [c for r, c in positions]
        rmin, rmax = min(rows_c), max(rows_c)
        cmin, cmax = min(cols_c), max(cols_c)

        # Extract template
        template = grid[rmin:rmax+1, cmin:cmax+1]
