        for tr in range(th):
            for tc in range(tw):
                if (tr, tc) in color_set or (tr, tc) in visited:
                    continue
                # BFS to check if enclosed
                queue = deque([(tr, tc)])
                region = {(tr, tc)}
                enclosed = True
                while queue:
                    cr, cc = queue.popleft()
                    for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                        nr, nc = cr+dr, cc+dc
                        if (nr, nc) in region or (nr, nc) in color_set:
                            continue
                        if nr < 0 or nr >= th or nc < 0 or nc >= tw:
                            enclosed = False
                            continue
                        region.add((nr, nc))
